今有物不知其数　　其实这篇文章本来想作为我公众号的第一篇文章，无奈那时想开摆。由于本人的数论功底有限，因此该文的内容主要还是偏简单入门向，对新手较为友好。如有问题，欢迎交流指正。里面有些算法和这个问题关系没那么大，可以自行了解便不给出具体证明了。下文中即为a和b的最大公约数，即为a整除b。









我国古代名著《孙子算经》中的“物不知数”问题：“今有物不知其数，三三数之剩二，五五数之剩二，七七数之剩三，问物几何？”
一.基础概念(1)同余






概念
若两个数与除以的余数相同,或者说可以被整除,则说明同余于模在上式中称为模数,是对模的剩余,并且由于同余具有对称性,因此和在这里可以互换同余还具备很多美好的性质,就不在这里再一一展开了

这很好理解，例如3和5同余于2
(2)线性同余方程






概念
即,给定,为未知数,上述方程可变形为的形式,显然,那么该问题有解的充要条件为,我们一般使用扩展欧几里得算法解决这类问题









练习
洛谷-P1082


int exgcd(int a,int b,int &amp;x,int &amp;y){
	if(b==0) {
		//a * x + 0 = a;
		x=1; y=0;
		return a;
	}
    //( a , b ) = ( b , a % b ) = d 由该结论我们可以进行逆推
	//b * y + a % b * x = ( a , b );
	//b * y + (a - [a / b] * b) * x = ( a , b );
	//a * x + b * ( y - [a / b] * x ) = d;
	int d = exgcd(b,a%b,y,x);
	y -= a / b * x;
	return d;
}


(3)逆元







练习
洛谷-P3811








概念
这里的逆元是定义在模意义的乘法运算中如果一个线性同余方程,则称为的逆元,记作显然该问题仍然能通过扩展欧几里得算法解决,其他办法还有快速幂等,对于求多个数的逆元,还有更为精妙的线性做法逆元最为直接的应用便是在除法取模上,将问题转化为乘逆元取模需要注意的是,快速幂能求逆元的条件是为(素数),因为它基于费马小定理,下给出代码实现


int qmi(int a,int b,int p){
	int res = 1;
	while(b){
		if(b&amp;1) res = (ll)res * a % p;
		b &gt;&gt;= 1;
		a = (ll) a * a % p;
	}
	return res;
}
int rev(int a,int p){
    return qmi(a,p-2,p);
}



二.CRT(中国剩余定理)








给定两两互质的数,给定方程组令 令为模的逆通解为,构造M的目的是为了在时结果均为0







练习
洛谷-P1495


#include &lt;bits/stdc++.h&gt;
using namespace std;
typedef long long ll;
ll a[16],m[16];
ll exgcd(ll a,ll b,ll &amp;x,ll &amp;y){
   if(b==0) {
      x=1; y=0;
      return a;
   }
   ll d = exgcd(b,a%b,y,x);
   y -= a / b * x;
   return d;
}
int main(){
	ll mul = 1,ans = 0;
	int n;
	cin&gt;&gt;n;
	for(int i=0;i&lt;n;++i) {
       scanf("%lld%lld",&amp;m[i],&amp;a[i]);
       mul *= m[i];
	}
	for(int i=0;i&lt;n;++i){
		ll x=0,y=0;
		exgcd(mul/m[i],m[i],x,y);
		ans+=a[i]*(mul/m[i])*((x%m[i]+m[i])%m[i]);
	}
	cout&lt;&lt;ans%mul&lt;&lt;endl;
}



三.EXCRT(扩展中国剩余定理)








在的基础上考虑两两不互质考虑对同余式进行合并通解为,将新代入可得上式得观察上式可令则转化为的形式，这便合二为一了







练习
此题过程可能导致long long溢出,意味着你无法通过下面代码通过此题，考虑使用__int128
洛谷-P4777


#include &lt;bits/stdc++.h&gt;
using namespace std;
typedef long long ll;
ll exgcd(ll a,ll b,ll &amp;x,ll &amp;y){
   if(b==0) {
      x=1; y=0;
      return a;
   }
   ll d = exgcd(b,a%b,y,x);
   y -= a / b * x;
   return d;
}

int main(){
   int n;
   bool has_answer = true;
   scanf("%d",&amp;n);	
   ll a1,m1;
   scanf("%lld%lld",&amp;a1,&amp;m1);
   for(int i=0;i&lt;n-1;++i){
      ll a2,m2;
      scanf("%lld%lld",&amp;a2,&amp;m2);
      ll k1,k2;
      ll d = exgcd(a1,a2,k1,k2);
      if((m2-m1)%d) {
         has_answer = false;
         break;
      }
      k1 *= (m2-m1)/d;
      ll t = abs(a2/d);
      k1 = (k1%t+t)%t;
      m1 = a1*k1+m1;
      a1 = abs(a1/d*a2);
   }
   if(has_answer) printf("%lld",(m1%a1+a1)%a1);
   else printf("-1");
}
